#include <bits/stdc++.h>
using namespace std;
int main(){
	int n,a[21],g[100005],m;
	string s;
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>a[i];
		g[i]=a[i];
		for(int j=1;j<=i/2;j++)g[i]=max(g[i],g[j]+g[i-j]);
	}
	cin>>m>>s;
	for(int i=n+1;i<=m;i++){
		g[i]=0;
		for(int j=1;j<=i/2;j++)g[i]=max(g[i],g[j]+g[i-j]);
	}
	int ans=0;
	int p=s.find("abc");
	while(p!=string::npos && p<s.size()){
		int l=p,r=p+2;
		while(s.find("abc",p+3)==p+3)r+=3,p+=3;
		ans+=g[(r-l+1)/3];
		p=s.find("abc",p+3); 
	}
	cout<<ans;
	return 0;
}
